from itertools import permutations
players = ['Z','N','C']
v = {frozenset():0, frozenset('Z'):30, frozenset('N'):25, frozenset('C'):20,
     frozenset('ZN'):72, frozenset('ZC'):68, frozenset('NC'):58, frozenset('ZNC'):105}
marg = {p:[] for p in players}
for perm in permutations(players):
    s = frozenset()
    for p in perm:
        s2 = frozenset(s|frozenset(p))
        marg[p].append(v[s2]-v[s])
        s = s2
shapley = {p:sum(marg[p])/6 for p in players}
print('Shapley:', shapley)
print('Pairwise:', shapley['Z']+shapley['N'], shapley['Z']+shapley['C'], shapley['N']+shapley['C'])
